
'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { Bus, UserCog, User, ShieldCheck, LogIn, Loader2, AlertTriangle } from "lucide-react";
import Link from 'next/link';
import { signInWithEmailAndPassword } from "firebase/auth";
import { auth } from '@/lib/firebase';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';

const roleCredentials = {
  parent: 'parent@yellowtransit.com',
  admin: 'admin@yellowtransit.com',
  driver: 'driver@yellowtransit.com',
};

export default function LoginPage() {
  const router = useRouter();
  const { toast } = useToast();
  const [role, setRole] = useState('admin');
  const [email, setEmail] = useState(roleCredentials.admin);
  const [password, setPassword] = useState('12345678');
  const [isLoading, setIsLoading] = useState(false);

  // A simple check to see if the environment variables are loaded.
  const isFirebaseConfigured = !!process.env.NEXT_PUBLIC_FIREBASE_API_KEY;
  
  const handleRoleChange = (newRole: 'parent' | 'admin' | 'driver') => {
    setRole(newRole);
    setEmail(roleCredentials[newRole]);
    setPassword('12345678'); // Reset password to default for the selected role
  };


  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFirebaseConfigured) {
        toast({
          variant: 'destructive',
          title: "Configuration Error",
          description: "Firebase is not configured. Please add your credentials to the .env file.",
        });
        return;
    };

    setIsLoading(true);

    try {
      await signInWithEmailAndPassword(auth, email, password);
      toast({
        title: "Login Successful",
        description: `Welcome! Redirecting to the ${role} dashboard.`,
      });
      router.push(`/dashboard/${role}`);
    } catch (error) {
      toast({
        variant: 'destructive',
        title: "Login Failed",
        description: "Invalid email or password. Please check your credentials or that the user has been created in Firebase Authentication.",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen flex-col items-center justify-center bg-muted/40 p-4">
      <div className="absolute top-4 left-4 z-10 hidden md:flex">
        <div className="flex items-center justify-center gap-2">
            <Bus className="h-6 w-6 text-primary" />
            <span className="text-lg font-semibold font-headline">Yellow Transit</span>
        </div>
      </div>

      <Card className="w-full max-w-sm z-10">
        <CardHeader className="text-center">
            <div className="mx-auto bg-primary/20 text-primary p-3 rounded-full w-fit mb-4">
                <Bus className="h-8 w-8" />
            </div>
            <CardTitle className="text-2xl font-bold font-headline">Yellow Transit Login</CardTitle>
            <CardDescription>Select your role to sign in.</CardDescription>
        </CardHeader>
        <CardContent>
          {!isFirebaseConfigured && (
              <Alert variant="destructive" className="mb-4">
                <AlertTriangle className="h-4 w-4" />
                <AlertTitle>Firebase Not Configured</AlertTitle>
                <AlertDescription>
                  Please add your Firebase credentials to the .env file to enable login.
                </AlertDescription>
              </Alert>
          )}
          <form onSubmit={handleLogin} className="space-y-4">
            <div className="space-y-2">
                <Label>I am a:</Label>
                <div className="grid grid-cols-3 gap-2">
                    <Button type="button" variant={role === 'parent' ? 'default' : 'outline'} onClick={() => handleRoleChange('parent')}>
                        <User className="mr-2 h-4 w-4" />Parent
                    </Button>
                    <Button type="button" variant={role === 'admin' ? 'default' : 'outline'} onClick={() => handleRoleChange('admin')}>
                        <UserCog className="mr-2 h-4 w-4" />Admin
                    </Button>
                    <Button type="button" variant={role === 'driver' ? 'default' : 'outline'} onClick={() => handleRoleChange('driver')}>
                        <ShieldCheck className="mr-2 h-4 w-4" />Driver
                    </Button>
                </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="email">Email</Label>
              <Input id="email" type="email" placeholder="m@example.com" required value={email} onChange={e => setEmail(e.target.value)} disabled={isLoading || !isFirebaseConfigured} />
            </div>
            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <Label htmlFor="password">Password</Label>
                <Link
                    href="#"
                    className="text-sm font-medium text-primary hover:underline"
                >
                    Forgot password?
                </Link>
              </div>
              <Input id="password" type="password" required value={password} onChange={e => setPassword(e.target.value)} disabled={isLoading || !isFirebaseConfigured} />
            </div>
            <Button type="submit" className="w-full" disabled={isLoading || !isFirebaseConfigured}>
              {isLoading ? (
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              ) : (
                <LogIn className="mr-2 h-4 w-4" />
              )}
              {isLoading ? 'Signing In...' : 'Sign In'}
            </Button>
          </form>
        </CardContent>
        <CardFooter>
             <p className="text-xs text-muted-foreground text-center w-full">
                © 2025 Yellow Transit. All rights reserved.
             </p>
        </CardFooter>
      </Card>
    </div>
  );
}
